// n8n Code Node: Validate Scene Generator Input
// Place right after the Webhook node

const input = $input.first().json.body;
const errors = [];
const warnings = [];

// ──────────────────────────────────────
// 1. REQUIRED KEYS
// ──────────────────────────────────────
if (!input.script || typeof input.script !== 'string') {
  errors.push('Missing or invalid "script": must be a non-empty string');
}

if (!input.segments || !Array.isArray(input.segments)) {
  errors.push('Missing or invalid "segments": must be an array');
}

if (!input.style || typeof input.style !== 'string') {
  warnings.push('Missing "style": will default to "cinematic photorealistic"');
}

// ──────────────────────────────────────
// 2. SCRIPT VALIDATION
// ──────────────────────────────────────
if (input.script) {
  const wordCount = input.script.split(/\s+/).length;

  if (wordCount < 10) {
    errors.push(`Script too short: ${wordCount} words (min 10)`);
  }

  if (wordCount > 500) {
    warnings.push(`Script is long: ${wordCount} words — LLM output may be truncated`);
  }
}

// ──────────────────────────────────────
// 3. SEGMENTS VALIDATION
// ──────────────────────────────────────
if (Array.isArray(input.segments)) {
  if (input.segments.length === 0) {
    errors.push('Segments array is empty');
  }

  if (input.segments.length < 3) {
    warnings.push(`Only ${input.segments.length} segments — may produce thin scene plan`);
  }

  if (input.segments.length > 25) {
    warnings.push(`${input.segments.length} segments — LLM may struggle with this many`);
  }

  const seenIndexes = new Set();

  input.segments.forEach((seg, i) => {
    // Index exists and is integer
    if (seg.index === undefined || typeof seg.index !== 'number') {
      errors.push(`Segment ${i}: missing or invalid "index"`);
    }

    // Duplicate index check
    if (seenIndexes.has(seg.index)) {
      errors.push(`Segment ${i}: duplicate index ${seg.index}`);
    }
    seenIndexes.add(seg.index);

    // Words exists and is string
    if (!seg.words || typeof seg.words !== 'string') {
      errors.push(`Segment ${i} (index ${seg.index}): missing or invalid "words"`);
    }

    // Words not empty
    if (seg.words && seg.words.trim().length === 0) {
      errors.push(`Segment ${i} (index ${seg.index}): "words" is empty`);
    }
  });

  // Check chronological index order
  for (let i = 1; i < input.segments.length; i++) {
    if (input.segments[i].index <= input.segments[i - 1].index) {
      errors.push(`Segments not in order: index ${input.segments[i].index} after ${input.segments[i - 1].index}`);
    }
  }
}

// ──────────────────────────────────────
// 4. OPTIONAL FIELDS CHECK
// ──────────────────────────────────────
const VALID_STYLES = [
  'cinematic', 'cinematic photorealistic', 'abstract',
  'painterly', 'anime', 'watercolor', 'noir',
  'retro', 'minimalist', 'surreal'
];

if (input.style && !VALID_STYLES.some(s => input.style.toLowerCase().includes(s))) {
  warnings.push(`Style "${input.style}" not in known presets — LLM will interpret freely`);
}

if (input.aspect_ratio) {
  const validRatios = ['9:16', '16:9', '1:1', '4:5'];
  if (!validRatios.includes(input.aspect_ratio)) {
    warnings.push(`Aspect ratio "${input.aspect_ratio}" not standard`);
  }
}

// ──────────────────────────────────────
// 5. BUILD CLEAN PAYLOAD
// ──────────────────────────────────────
const valid = errors.length === 0;

if (!valid) {
  return {
    json: {
      valid: false,
      errors,
      warnings
    }
  };
}

// Clean payload — only what the LLM needs
const cleanPayload = {
  script: input.script.trim(),
  style: (input.style || 'cinematic photorealistic').trim(),
  segments: input.segments.map(s => ({
    index: s.index,
    words: s.words.trim()
  }))
};

// Pass-through metadata for later merge
const metadata = {
  source_folder: input.source_folder || '',
  aspect_ratio: input.aspect_ratio || '9:16',
  segment_count: input.segments.length
};

return {
  json: {
    valid: true,
    errors: [],
    warnings,
    payload: cleanPayload,
    metadata
  }
};

// n8n Code Node: Validate LLM Scene Output + Add FX/Duration
// Place after the LLM Chain node

const raw = $input.first().json.text;
const errors = [];
const warnings = [];

// ──────────────────────────────────────
// 1. PARSE JSON
// ──────────────────────────────────────
let data;
try {
  data = JSON.parse(raw);
} catch (e) {
  // Try to extract JSON from markdown fences
  const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try {
      data = JSON.parse(match[1].trim());
    } catch (e2) {
      return { json: { valid: false, errors: ['Failed to parse JSON: ' + e2.message], warnings: [] } };
    }
  } else {
    return { json: { valid: false, errors: ['Failed to parse JSON: ' + e.message], warnings: [] } };
  }
}

// ──────────────────────────────────────
// 2. VALIDATE ANALYSIS
// ──────────────────────────────────────
if (!data.analysis || typeof data.analysis !== 'object') {
  errors.push('Missing "analysis" object');
} else {
  const requiredAnalysis = ['mood', 'environment', 'color_palette', 'tone', 'visual_style'];
  requiredAnalysis.forEach(key => {
    if (!data.analysis[key] || typeof data.analysis[key] !== 'string') {
      warnings.push(`analysis.${key} missing or empty — will not block`);
    }
  });
}

// ──────────────────────────────────────
// 3. VALIDATE SCENES ARRAY
// ──────────────────────────────────────
if (!data.scenes || !Array.isArray(data.scenes)) {
  return { json: { valid: false, errors: ['Missing "scenes" array'], warnings } };
}

if (data.scenes.length === 0) {
  return { json: { valid: false, errors: ['Scenes array is empty'], warnings } };
}

// ──────────────────────────────────────
// 4. VALIDATE EACH SCENE
// ──────────────────────────────────────
const VALID_ROLES = ['hook', 'buildup', 'peak', 'transition', 'text_accent', 'cta'];
const VALID_TYPES = ['image', 'video', 'text'];
const MOTION_WORDS_BANNED = /\b(dolly|pan|zoom|tracking|orbit|crane|tilt|drift|time-lapse|transition|morphing|sequence)\b/i;
const NON_ASCII = /[^\x00-\x7F]/;

const seenIndexes = new Set();
let lastShotType = '';

data.scenes.forEach((scene, i) => {
  const label = `Scene ${i} (index ${scene.segment_index})`;

  // segment_index
  if (scene.segment_index === undefined || typeof scene.segment_index !== 'number') {
    errors.push(`${label}: missing or invalid segment_index`);
  }
  if (seenIndexes.has(scene.segment_index)) {
    errors.push(`${label}: duplicate segment_index ${scene.segment_index}`);
  }
  seenIndexes.add(scene.segment_index);

  // title
  if (!scene.title || typeof scene.title !== 'string') {
    errors.push(`${label}: missing title`);
  } else if (scene.title.split(/\s+/).length > 8) {
    warnings.push(`${label}: title "${scene.title}" is long (${scene.title.split(/\s+/).length} words)`);
  }

  // narrative_role
  if (!VALID_ROLES.includes(scene.narrative_role)) {
    errors.push(`${label}: invalid narrative_role "${scene.narrative_role}"`);
  }

  // type_of_scene
  if (!VALID_TYPES.includes(scene.type_of_scene)) {
    errors.push(`${label}: invalid type_of_scene "${scene.type_of_scene}"`);
  }

  // image_prompt
  if (!scene.image_prompt || typeof scene.image_prompt !== 'string') {
    if (scene.type_of_scene !== 'text') {
      errors.push(`${label}: missing image_prompt for non-text scene`);
    }
  } else {
    // Check for motion verbs in image_prompt
    if (MOTION_WORDS_BANNED.test(scene.image_prompt)) {
      warnings.push(`${label}: image_prompt may contain motion verbs`);
    }

    // Check for non-ASCII
    if (NON_ASCII.test(scene.image_prompt)) {
      warnings.push(`${label}: image_prompt contains non-ASCII characters`);
      // Auto-fix: strip non-ASCII
      scene.image_prompt = scene.image_prompt.replace(/[^\x00-\x7F]/g, '');
    }

    // Check prompt length
    if (scene.image_prompt.length < 30) {
      warnings.push(`${label}: image_prompt very short (${scene.image_prompt.length} chars)`);
    }
  }

  // motion_in_image
  if (scene.type_of_scene === 'text' && scene.motion_in_image !== null) {
    warnings.push(`${label}: text scene should have motion_in_image = null`);
    scene.motion_in_image = null; // auto-fix
  }
  if (scene.type_of_scene !== 'text' && !scene.motion_in_image) {
    warnings.push(`${label}: non-text scene has no motion_in_image`);
  }

  // text_content
  if (scene.type_of_scene === 'text') {
    if (!scene.text_content || typeof scene.text_content !== 'string') {
      errors.push(`${label}: text scene missing text_content`);
    }
  } else {
    if (scene.text_content !== null && scene.text_content !== undefined) {
      warnings.push(`${label}: non-text scene has text_content — setting to null`);
      scene.text_content = null; // auto-fix
    }
  }
});

// ──────────────────────────────────────
// 5. STRUCTURE CHECKS
// ──────────────────────────────────────

// First scene should be hook
if (data.scenes[0] && data.scenes[0].narrative_role !== 'hook') {
  warnings.push(`First scene role is "${data.scenes[0].narrative_role}" — expected "hook"`);
}

// Last scene should be cta
const lastScene = data.scenes[data.scenes.length - 1];
if (lastScene && lastScene.narrative_role !== 'cta') {
  warnings.push(`Last scene role is "${lastScene.narrative_role}" — expected "cta"`);
}

// Type mix check
const typeCounts = { video: 0, image: 0, text: 0 };
data.scenes.forEach(s => { if (typeCounts[s.type_of_scene] !== undefined) typeCounts[s.type_of_scene]++; });
const total = data.scenes.length;

if (typeCounts.text < 2 && total >= 6) {
  warnings.push(`Only ${typeCounts.text} text scene(s) — recommend minimum 2`);
}

const videoPct = Math.round(typeCounts.video / total * 100);
const imagePct = Math.round(typeCounts.image / total * 100);
const textPct = Math.round(typeCounts.text / total * 100);

// ──────────────────────────────────────
// 6. ADD FX + DURATION
// ──────────────────────────────────────
const FX_VIDEO = [
  'slow_push', 'zoom_in', 'zoom_out', 'pull_back',
  'pan_left', 'pan_right', 'tilt_up', 'tilt_down',
  'dolly_in', 'dolly_out', 'crane_up', 'crane_down',
  'orbit_left', 'orbit_right', 'handheld_drift', 'slow_motion'
];
const FX_IMAGE = ['slow_push', 'zoom_in', 'zoom_out', 'static_hold', 'handheld_drift', 'slow_motion'];
const FX_TEXT = ['static_hold', 'gentle zoom_in', 'slow_push', 'zoom_out'];

const randomFrom = (arr) => arr[Math.floor(Math.random() * arr.length)];
const randomDuration = () => +(2 + Math.random() * 1.5).toFixed(1);

let lastFx = '';

data.scenes.forEach(scene => {
  let pool;
  if (scene.type_of_scene === 'text') pool = FX_TEXT;
  else if (scene.type_of_scene === 'image') pool = FX_IMAGE;
  else pool = FX_VIDEO;

  let fx = randomFrom(pool);
  let attempts = 0;
  while (fx === lastFx && attempts < 5) {
    fx = randomFrom(pool);
    attempts++;
  }
  lastFx = fx;

  scene.fx = fx;
  scene.duration = randomDuration();
});

// ──────────────────────────────────────
// 7. OUTPUT
// ──────────────────────────────────────
const valid = errors.length === 0;

return {
  json: {
    valid,
    errors,
    warnings,
    type_mix: {
      video: `${typeCounts.video} (${videoPct}%)`,
      image: `${typeCounts.image} (${imagePct}%)`,
      text: `${typeCounts.text} (${textPct}%)`
    },
    analysis: data.analysis || {},
    scenes: data.scenes,
    scene_count: data.scenes.length
  }
};
